// src/pages/LabourDashboard.jsx

import { useEffect, useState } from "react";
import axios from "axios";
import Navbar from "../components/Navbar";

export default function LabourDashboard() {

  const user = JSON.parse(
    localStorage.getItem("user")
  );

  const [requests, setRequests] =
    useState([]);

  const [price, setPrice] =
    useState({});

  useEffect(() => {

    getRequests();

  }, []);

  const getRequests = async () => {

    try {

      const res = await axios.get(

        `http://localhost:5000/api/request/labour/${user._id}`

      );

      setRequests(res.data);

    } catch (err) {

      console.log(err);

    }
  };

  const respondRequest =
    async (id, action) => {

      try {

        await axios.put(

          `http://localhost:5000/api/request/labour-response/${id}`,

          {
            price: price[id] || 0,
            action
          }

        );

        getRequests();

      } catch (err) {

        console.log(err);

      }
    };

  return (

    <div style={styles.page}>

      <Navbar />

      <div style={styles.container}>

        <div style={styles.card}>

          <h2 style={styles.heading}>
            Request Received
          </h2>

          {requests.length === 0 && (

            <p style={styles.noRequest}>
              No Requests Found
            </p>

          )}

          {requests.map((req) => (

            <div
              key={req._id}
              style={styles.requestBox}
            >

              {/* TOP */}

              <div style={styles.topRow}>

                <h3 style={styles.name}>
                  {req.customerName}
                </h3>

                <span style={styles.status}>
                  {req.status}
                </span>

              </div>

              {/* DETAILS */}

              <div style={styles.details}>

                <p>
                  <b>Work:</b>
                  {" "}
                  {req.workType}
                </p>

                <p>
                  <b>Location:</b>
                  {" "}
                  {req.location}
                </p>

                <p>
                  <b>Date:</b>
                  {" "}
                  {req.date}
                </p>

                <p>
                  <b>Customer Decision:</b>
                  {" "}
                  {req.customerDecision}
                </p>

              </div>

              {/* PRICE */}

              <input
                type="text"
                placeholder="Enter Price ₹"
                style={styles.input}
                value={price[req._id] || ""}
                onChange={(e) => {

                  const value =
                    e.target.value.replace(
                      /\D/g,
                      ""
                    );

                  setPrice({

                    ...price,

                    [req._id]: value

                  });

                }}
              />

              {/* BUTTONS */}

              {req.status ===
                "Pending" && (

                <div style={styles.btnRow}>

                  <button
                    style={styles.acceptBtn}

                    onClick={() =>
                      respondRequest(
                        req._id,
                        "Accepted"
                      )
                    }
                  >

                    Accept

                  </button>

                  <button
                    style={styles.rejectBtn}

                    onClick={() =>
                      respondRequest(
                        req._id,
                        "Rejected"
                      )
                    }
                  >

                    Reject

                  </button>

                </div>

              )}

              {/* FEEDBACK */}

              {req.feedback &&
                req.feedback.rating > 0 && (

                <div
                  style={styles.feedbackBox}
                >

                  {/* STARS */}

                  <div style={styles.starRow}>

                    {[1, 2, 3, 4, 5].map(
                      (star) => (

                      <span
                        key={star}
                        style={{

                          fontSize: "20px",

                          color:
                            req.feedback
                              .rating >= star
                              ? "#facc15"
                              : "#d1d5db"

                        }}
                      >

                        ★

                      </span>

                    ))}

                  </div>

                  {/* COMMENT */}

                  <p style={styles.comment}>

                    {req.feedback.comment}

                  </p>

                </div>

              )}

            </div>

          ))}

        </div>

      </div>

    </div>
  );
}

/* ================= WHITE UI ================= */

const styles = {

  page: {
    background: "#f4f7fb",
    minHeight: "100vh"
  },

  container: {
    padding: "30px",
    maxWidth: "900px",
    margin: "auto"
  },

  card: {
    background: "white",
    padding: "25px",
    borderRadius: "18px",
    boxShadow:
      "0 4px 15px rgba(0,0,0,0.05)"
  },

  heading: {
    marginBottom: "20px",
    color: "#111827",
    textAlign: "center"
  },

  noRequest: {
    textAlign: "center",
    color: "#6b7280"
  },

  requestBox: {
    border:
      "1px solid #e5e7eb",
    borderRadius: "14px",
    padding: "18px",
    marginBottom: "18px",
    background: "#ffffff"
  },

  topRow: {
    display: "flex",
    justifyContent: "space-between",
    alignItems: "center",
    marginBottom: "14px"
  },

  name: {
    margin: 0,
    color: "#111827"
  },

  status: {
    background: "#eff6ff",
    color: "#2563eb",
    padding: "6px 12px",
    borderRadius: "20px",
    fontSize: "12px",
    fontWeight: "bold"
  },

  details: {
    display: "flex",
    flexDirection: "column",
    gap: "6px",
    marginBottom: "16px",
    color: "#374151",
    fontSize: "14px"
  },

  input: {
    width: "100%",
    padding: "12px",
    borderRadius: "10px",
    border:
      "1px solid #d1d5db",
    outline: "none",
    boxSizing: "border-box",
    marginBottom: "14px",
    fontSize: "14px"
  },

  btnRow: {
    display: "flex",
    gap: "10px"
  },

  acceptBtn: {
    flex: 1,
    padding: "12px",
    background: "#16a34a",
    color: "white",
    border: "none",
    borderRadius: "10px",
    cursor: "pointer",
    fontWeight: "bold"
  },

  rejectBtn: {
    flex: 1,
    padding: "12px",
    background: "#dc2626",
    color: "white",
    border: "none",
    borderRadius: "10px",
    cursor: "pointer",
    fontWeight: "bold"
  },

  feedbackBox: {
    marginTop: "16px",
    background: "#f9fafb",
    padding: "14px",
    borderRadius: "10px"
  },

  starRow: {
    display: "flex",
    gap: "3px",
    marginBottom: "8px"
  },

  comment: {
    margin: 0,
    color: "#374151",
    fontSize: "14px"
  }

};
